    tiling.set_N(N);
    tiling.set_D(D);
    tiling.set_iStart(0);
    tiling.set_iEnd(0);
    tiling.set_outOffset(0);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
